// modules/stripe/webhooks/handleSubscriptionEvent.ts
import { Request, Response } from 'bun';
import { Result, ok, err } from '/lib/result';
import { parseBody } from '/lib/validate';
import { verifyWebhookSignature } from '/lib/stripe';
import { updateSubscription } from '/modules/subscriptions/lib/update';

export async function handleSubscriptionEvent(req: Request): Promise<Response> {
  const body = await parseBody<{ id: string, type: string, data: any }>(req);

  if (!body) {
    return err({ code: 'INVALID_REQUEST', message: 'Invalid request body' }).toResponse();
  }

  try {
    // Verify the webhook signature
    const isValidSignature = await verifyWebhookSignature(req.headers['stripe-signature'], req.body);
    if (!isValidSignature) {
      return err({ code: 'UNAUTHORIZED', message: 'Invalid webhook signature' }).toResponse();
    }

    // Update the subscription based on the event type and data
    switch (body.type) {
      case 'invoice.payment_succeeded':
        await updateSubscription(body.data.object.subscription, { status: 'paid' });
        break;
      case 'invoice.payment_failed':
        await updateSubscription(body.data.object.subscription, { status: 'failed' });
        break;
      default:
        return err({ code: 'UNKNOWN_EVENT', message: `Unknown event type: ${body.type}` }).toResponse();
    }

    return ok({ message: 'Subscription updated successfully' }).toResponse();
  } catch (error) {
    return err({ code: 'INTERNAL_ERROR', message: 'Failed to update subscription' }).toResponse();
  }
}

